# agentic_F1-skeptic/S38-T2-A-E1: packet-only solve (no prior lives)
class TokenBucket:
    def __init__(self, rate):
        self.tokens = rate
    def allow(self):
        if self.tokens >= 1:
            self.tokens -= 1
            return True
        return False
b = TokenBucket(3)allows = [b.allow() for _ in range(3)]
print(sum(1 for a in allows if a))
print("third", allows[2])
print("ok", True)

